using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo([Description("The message to echo")] string message)
        => $"Echo: {message}";

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime()
        => $"Server time: {DateTime.UtcNow:O}";
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        Uri = "config://app/settings",
        Name = "App Settings",
        Description = "Returns the current application configuration.",
        MimeType = "application/json")]
    public static string GetAppSettings()
        => """
           {
             "environment": "production",
             "version": "1.0.0",
             "features": {
               "darkMode": true,
               "betaAccess": false
             },
             "maxConnections": 100
           }
           """;

    [McpServerResource(
        Uri = "config://app/health",
        Name = "Health Status",
        Description = "Returns the server health status.",
        MimeType = "application/json")]
    public static string GetHealthStatus()
        => $$"""
             {
               "status": "healthy",
               "uptime": "{{DateTime.UtcNow:O}}",
               "services": {
                 "database": "connected",
                 "cache": "connected"
               }
             }
             """;
}

